class Solution:
    def stoneGameII(self, piles):
        n = len(piles)
        suffix = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffix[i] = suffix[i + 1] + piles[i]
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def best(i, m):
            if i >= n:
                return 0
            if i + 2 * m >= n:
                return suffix[i]
            res = 0
            for x in range(1, 2 * m + 1):
                if i + x > n:
                    break
                res = max(res, suffix[i] - best(i + x, max(m, x)))
            return res
        return best(0, 1)

